assignments.value:
={{ (() => {
  const blob = String($node["[BUGFIX] CB Query"].json.data || '');
  let arr = [];
  for (const line of blob.split('\n')) {
    if (!line.startsWith('data: ')) continue;
    try {
      const obj = JSON.parse(line.slice(6));
      const text = obj.result && obj.result.content && obj.result.content[0] && obj.result.content[0].text;
      if (text) arr = JSON.parse(text);
    } catch (e) {}
  }
  const reqId = $node["[ENTRY] Ctx 提取"].json.reqId;
  return arr.filter(it => Array.isArray(it.tags) && it.tags.includes(reqId) && it.tags.includes('bugfix')).length + 1;
})() }}
